const express = require('express');
const redis = require('redis');
const { body, query, validationResult } = require('express-validator');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();
app.use(express.json());
app.use(helmet());

const client = redis.createClient({
  url: process.env.REDIS_URL || 'redis://localhost:6379',
  password: process.env.REDIS_PASSWORD
});

client.connect().catch(console.error);

const ALLOWED_REDIS_COMMANDS = new Set([
  'GET',
  'SET',
  'DEL',
  'EXISTS',
  'TTL',
  'EXPIRE',
  'KEYS',
  'SCAN',
  'INFO',
  'DBSIZE',
  'PING'
]);

const ADMIN_API_KEY = process.env.ADMIN_API_KEY;

if (!ADMIN_API_KEY) {
  console.error('ADMIN_API_KEY environment variable must be set');
  process.exit(1);
}

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  message: 'Too many requests from this IP'
});

app.use(limiter);

function authenticateAdmin(req, res, next) {
  const apiKey = req.headers['x-api-key'];
  
  if (!apiKey || apiKey !== ADMIN_API_KEY) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  
  next();
}

function sanitizePattern(pattern) {
  if (typeof pattern !== 'string') {
    throw new Error('Pattern must be a string');
  }
  
  if (pattern.length > 100) {
    throw new Error('Pattern too long');
  }
  
  const allowedChars = /^[a-zA-Z0-9:_\-*?\[\]]+$/;
  if (!allowedChars.test(pattern)) {
    throw new Error('Pattern contains invalid characters');
  }
  
  return pattern;
}

function validateRedisCommand(command, args) {
  if (typeof command !== 'string') {
    throw new Error('Command must be a string');
  }
  
  const upperCommand = command.toUpperCase();
  
  if (!ALLOWED_REDIS_COMMANDS.has(upperCommand)) {
    throw new Error(`Command '${command}' is not allowed`);
  }
  
  if (!Array.isArray(args)) {
    throw new Error('Arguments must be an array');
  }
  
  if (args.length > 10) {
    throw new Error('Too many arguments');
  }
  
  for (const arg of args) {
    if (typeof arg !== 'string' && typeof arg !== 'number') {
      throw new Error('Arguments must be strings or numbers');
    }
    
    if (typeof arg === 'string' && arg.length > 1000) {
      throw new Error('Argument too long');
    }
  }
  
  if (upperCommand === 'KEYS' && args.length === 1) {
    sanitizePattern(args[0]);
  }
  
  return { command: upperCommand, args };
}

app.get('/api/keys/search',
  authenticateAdmin,
  [
    query('pattern')
      .trim()
      .notEmpty()
      .withMessage('Pattern is required')
      .isLength({ max: 100 })
      .withMessage('Pattern too long')
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    
    try {
      const pattern = sanitizePattern(req.query.pattern);
      
      const keys = [];
      let cursor = 0;
      
      do {
        const result = await client.scan(cursor, {
          MATCH: pattern,
          COUNT: 100
        });
        
        cursor = result.cursor;
        keys.push(...result.keys);
        
        if (keys.length > 1000) {
          break;
        }
      } while (cursor !== 0);
      
      res.json({
        pattern: pattern,
        count: keys.length,
        keys: keys.slice(0, 1000),
        truncated: keys.length > 1000
      });
      
    } catch (error) {
      console.error('Search error:', error.message);
      res.status(400).json({ error: error.message });
    }
  }
);

app.post('/api/redis/execute',
  authenticateAdmin,
  [
    body('command')
      .trim()
      .notEmpty()
      .withMessage('Command is required')
      .isLength({ max: 50 })
      .withMessage('Command too long'),
    body('args')
      .isArray()
      .withMessage('Args must be an array')
      .optional()
  ],
  async (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    
    try {
      const { command, args = [] } = req.body;
      
      const validated = validateRedisCommand(command, args);
      
      let result;
      
      if (validated.command === 'SCAN') {
        const cursor = args[0] || 0;
        const options = {};
        
        for (let i = 1; i < args.length; i += 2) {
          if (args[i] === 'MATCH' && args[i + 1]) {
            options.MATCH = sanitizePattern(args[i + 1]);
          } else if (args[i] === 'COUNT' && args[i + 1]) {
            options.COUNT = parseInt(args[i + 1], 10);
          }
        }
        
        result = await client.scan(cursor, options);
      } else {
        result = await client.sendCommand([validated.command, ...validated.args]);
      }
      
      res.json({
        command: validated.command,
        result: result
      });
      
    } catch (error) {
      console.error('Execute error:', error.message);
      res.status(400).json({ error: error.message });
    }
  }
);

app.get('/api/health', async (req, res) => {
  try {
    await client.ping();
    res.json({ status: 'healthy', redis: 'connected' });
  } catch (error) {
    res.status(503).json({ status: 'unhealthy', redis: 'disconnected' });
  }
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(`Redis management dashboard running on port ${PORT}`);
});

process.on('SIGTERM', async () => {
  await client.quit();
  process.exit(0);
});